import{_ as t,o as a,c as s,aj as i}from"./chunks/framework.DEEoir6m.js";const c=JSON.parse('{"title":"FAQ","description":"Frequently asked questions about GISPulse — the declarative geospatial engine.","frontmatter":{"title":"FAQ","description":"Frequently asked questions about GISPulse — the declarative geospatial engine."},"headers":[],"relativePath":"en/faq.md","filePath":"en/faq.md"}'),r={name:"en/faq.md"};function o(n,e,l,d,u,h){return a(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h1><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><h3 id="what-is-gispulse" tabindex="-1">What is GISPulse? <a class="header-anchor" href="#what-is-gispulse" aria-label="Permalink to &quot;What is GISPulse?&quot;">​</a></h3><p>GISPulse is a declarative geospatial engine. You describe spatial processing pipelines as JSON rules, and GISPulse executes them on your data. It handles format conversion, CRS reprojection, spatial operations, and output generation — all without writing code.</p><p>Think of it as <strong>what dbt is to data engineering, but for GIS</strong>: reproducible, versionable, auditable spatial workflows.</p><h3 id="what-does-rules-as-config-mean" tabindex="-1">What does &quot;rules-as-config&quot; mean? <a class="header-anchor" href="#what-does-rules-as-config-mean" aria-label="Permalink to &quot;What does &quot;rules-as-config&quot; mean?&quot;">​</a></h3><p>Instead of writing Python scripts or building visual workflows in a GUI, you define your spatial processing as a JSON file. Each rule specifies a capability (e.g., <code>buffer</code>, <code>spatial_join</code>, <code>filter</code>), its parameters, and its inputs. The engine reads the file and executes the pipeline.</p><p>This approach brings several advantages:</p><ul><li><strong>Reproducibility</strong> — same input + same rules = same output, every time</li><li><strong>Version control</strong> — your entire pipeline is a JSON file under Git</li><li><strong>Readability</strong> — GIS analysts can understand and modify rules without knowing Python</li><li><strong>Portability</strong> — the same rules run on DuckDB locally or PostGIS in production</li></ul><h3 id="how-does-gispulse-differ-from-fme" tabindex="-1">How does GISPulse differ from FME? <a class="header-anchor" href="#how-does-gispulse-differ-from-fme" aria-label="Permalink to &quot;How does GISPulse differ from FME?&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>GISPulse</th><th>FME</th></tr></thead><tbody><tr><td><strong>Model</strong></td><td>Open source (AGPL-3.0)</td><td>Proprietary, 5–15k EUR/year</td></tr><tr><td><strong>Approach</strong></td><td>Declarative JSON rules</td><td>Visual GUI workbenches</td></tr><tr><td><strong>Portability</strong></td><td>Embedded DuckDB, zero install</td><td>Requires FME Desktop/Server</td></tr><tr><td><strong>API</strong></td><td>REST API + Python SDK included</td><td>Paid add-ons</td></tr><tr><td><strong>Version control</strong></td><td>Native JSON under Git</td><td>XML export, not Git-friendly</td></tr><tr><td><strong>Vendor lock-in</strong></td><td>None</td><td>High</td></tr></tbody></table><p>FME excels at complex visual ETL with hundreds of transformers. GISPulse targets teams that want to automate, version, and deploy spatial processing in modern CI/CD pipelines.</p><h3 id="how-does-gispulse-differ-from-qgis-processing" tabindex="-1">How does GISPulse differ from QGIS Processing? <a class="header-anchor" href="#how-does-gispulse-differ-from-qgis-processing" aria-label="Permalink to &quot;How does GISPulse differ from QGIS Processing?&quot;">​</a></h3><p>QGIS Processing is excellent for interactive GIS work but is not designed for headless, server-side, or API-driven execution. GISPulse complements QGIS: you can use the QGIS plugin to explore data interactively, then run the same rules headlessly in a pipeline via CLI or API.</p><h3 id="how-does-gispulse-differ-from-raw-postgis" tabindex="-1">How does GISPulse differ from raw PostGIS? <a class="header-anchor" href="#how-does-gispulse-differ-from-raw-postgis" aria-label="Permalink to &quot;How does GISPulse differ from raw PostGIS?&quot;">​</a></h3><p>PostGIS is the spatial engine that powers GISPulse in persistent mode. But instead of writing and maintaining raw SQL, you define rules in JSON. GISPulse generates the optimized SQL, handles CRS transformations, manages sessions, and provides a REST API on top. You get PostGIS power without PostGIS complexity.</p><hr><h2 id="formats-data" tabindex="-1">Formats &amp; Data <a class="header-anchor" href="#formats-data" aria-label="Permalink to &quot;Formats &amp; Data&quot;">​</a></h2><h3 id="what-formats-does-gispulse-support" tabindex="-1">What formats does GISPulse support? <a class="header-anchor" href="#what-formats-does-gispulse-support" aria-label="Permalink to &quot;What formats does GISPulse support?&quot;">​</a></h3><p>GISPulse supports 13+ spatial formats via PyOGRIO/GDAL:</p><ul><li><strong>Vector:</strong> GPKG, GeoJSON, Shapefile, GeoParquet, FlatGeobuf, CSV+WKT, KML</li><li><strong>Raster:</strong> GeoTIFF (Pro)</li><li><strong>Services:</strong> WFS, OGC API Features, PostGIS</li><li><strong>Tiles:</strong> PMTiles, MVT</li></ul><p>The I/O layer auto-detects formats. No prior conversion needed.</p><h3 id="can-i-use-gispulse-without-postgis" tabindex="-1">Can I use GISPulse without PostGIS? <a class="header-anchor" href="#can-i-use-gispulse-without-postgis" aria-label="Permalink to &quot;Can I use GISPulse without PostGIS?&quot;">​</a></h3><p>Yes. Portable mode uses an embedded DuckDB engine that requires zero installation. It works entirely in memory with local files. PostGIS is only needed for persistent mode (triggers, scheduling, multi-user).</p><h3 id="what-is-the-dual-engine-architecture" tabindex="-1">What is the dual engine architecture? <a class="header-anchor" href="#what-is-the-dual-engine-architecture" aria-label="Permalink to &quot;What is the dual engine architecture?&quot;">​</a></h3><p>GISPulse abstracts the spatial engine behind an <code>ExecutionStrategy</code> interface:</p><ul><li><strong>DuckDB engine</strong> — embedded, serverless, portable. Ideal for local processing, CI/CD, batch jobs.</li><li><strong>PostGIS engine</strong> — persistent, server-based. Ideal for real-time triggers, continuous pipelines, multi-user access.</li></ul><p>The same JSON rules run on either engine. You choose the engine at execution time with <code>--engine duckdb</code> or <code>--engine postgis</code>.</p><hr><h2 id="production-deployment" tabindex="-1">Production &amp; Deployment <a class="header-anchor" href="#production-deployment" aria-label="Permalink to &quot;Production &amp; Deployment&quot;">​</a></h2><h3 id="is-gispulse-production-ready" tabindex="-1">Is GISPulse production-ready? <a class="header-anchor" href="#is-gispulse-production-ready" aria-label="Permalink to &quot;Is GISPulse production-ready?&quot;">​</a></h3><p>Yes. <strong>GISPulse v1.1.1</strong> is the current stable release: 117 capabilities, 3,600+ tests, multi-backend DuckDB / PostGIS engine, Prometheus metrics, RBAC, SSO (OIDC / SAML), audit logging and S3 storage. The CLI, REST API, Python SDK, QGIS plugin, ArcGIS add-in and Tauri desktop client are all shipped.</p><table tabindex="0"><thead><tr><th>Component</th><th>Status</th></tr></thead><tbody><tr><td>Engine (DuckDB / PostGIS / GPKG portable)</td><td><strong>Stable — v1.1.1</strong></td></tr><tr><td>CLI</td><td><strong>Stable</strong></td></tr><tr><td>REST API + Python SDK</td><td><strong>Stable</strong></td></tr><tr><td>117 capabilities (vector, attributes, classification, stats, topology, 3D pointcloud, raster, network, PostGIS SQL)</td><td><strong>Stable</strong></td></tr><tr><td>QGIS plugin / ArcGIS add-in / Tauri desktop</td><td><strong>Stable</strong></td></tr><tr><td>Web Portal (single-user Community, multi-user Pro / Team / Enterprise)</td><td><strong>Stable</strong></td></tr><tr><td>Visual node editor</td><td><strong>Beta</strong></td></tr></tbody></table><h3 id="how-do-i-deploy-gispulse" tabindex="-1">How do I deploy GISPulse? <a class="header-anchor" href="#how-do-i-deploy-gispulse" aria-label="Permalink to &quot;How do I deploy GISPulse?&quot;">​</a></h3><p>Four deployment modes:</p><ol><li><strong>pip install</strong> — <code>pip install gispulse</code> for CLI and SDK usage</li><li><strong>Docker</strong> — <code>docker-compose</code> with Caddy, Prometheus, Grafana</li><li><strong>Kubernetes</strong> — Helm chart for scalable deployments</li><li><strong>Desktop</strong> — Tauri app for standalone usage</li></ol><h3 id="can-i-migrate-from-fme" tabindex="-1">Can I migrate from FME? <a class="header-anchor" href="#can-i-migrate-from-fme" aria-label="Permalink to &quot;Can I migrate from FME?&quot;">​</a></h3><p>There is no automated FME-to-GISPulse migration tool. However, most FME workbenches can be expressed as GISPulse rules:</p><ol><li>Identify the transformers used in your FME workflow</li><li>Map each transformer to a GISPulse capability (buffer, spatial_join, filter, etc.)</li><li>Write the equivalent JSON rules file</li><li>Test with <code>gispulse run --engine duckdb</code></li></ol><p>For complex migrations, <a href="mailto:contact@gispulse.dev" target="_blank" rel="noreferrer">contact us</a> for assistance.</p><hr><h2 id="extensibility" tabindex="-1">Extensibility <a class="header-anchor" href="#extensibility" aria-label="Permalink to &quot;Extensibility&quot;">​</a></h2><h3 id="can-i-create-custom-capabilities" tabindex="-1">Can I create custom capabilities? <a class="header-anchor" href="#can-i-create-custom-capabilities" aria-label="Permalink to &quot;Can I create custom capabilities?&quot;">​</a></h3><p>Yes (Enterprise tier). GISPulse uses a capability registry with auto-discovery. You implement a Python class following the capability interface, register it, and it becomes available in your rules. Custom capabilities benefit from the same engine abstraction, session management, and API exposure as built-in ones.</p><h3 id="can-i-use-gispulse-as-a-library" tabindex="-1">Can I use GISPulse as a library? <a class="header-anchor" href="#can-i-use-gispulse-as-a-library" aria-label="Permalink to &quot;Can I use GISPulse as a library?&quot;">​</a></h3><p>Yes. The Python SDK provides programmatic access to all GISPulse features:</p><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> gispulse </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GISPulse</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">gp </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> GISPulse()</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">result </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> gp.run(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;rules.json&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">engine</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;duckdb&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>You can also use individual capabilities directly, build custom pipelines, or integrate GISPulse into existing Python applications.</p><hr><h2 id="security-licensing" tabindex="-1">Security &amp; Licensing <a class="header-anchor" href="#security-licensing" aria-label="Permalink to &quot;Security &amp; Licensing&quot;">​</a></h2><h3 id="how-is-data-security-handled" tabindex="-1">How is data security handled? <a class="header-anchor" href="#how-is-data-security-handled" aria-label="Permalink to &quot;How is data security handled?&quot;">​</a></h3><ul><li><strong>Portable mode:</strong> all data stays local. No network calls, no cloud dependencies.</li><li><strong>Persistent mode:</strong> data lives in your PostGIS instance. GISPulse never transmits data externally.</li><li><strong>Enterprise:</strong> SSO (SAML/OIDC), RBAC, audit logging, encrypted connections, on-premise deployment.</li></ul><h3 id="what-does-the-agpl-3-0-license-mean-for-me" tabindex="-1">What does the AGPL-3.0 license mean for me? <a class="header-anchor" href="#what-does-the-agpl-3-0-license-mean-for-me" aria-label="Permalink to &quot;What does the AGPL-3.0 license mean for me?&quot;">​</a></h3><p>If you use GISPulse internally (no distribution), AGPL-3.0 imposes no obligations. If you modify GISPulse and distribute it or offer it as SaaS, you must publish your modifications under the same license. Pro/Team/Enterprise tiers include a commercial license that removes this obligation.</p><hr><h2 id="support" tabindex="-1">Support <a class="header-anchor" href="#support" aria-label="Permalink to &quot;Support&quot;">​</a></h2><h3 id="where-can-i-get-help" tabindex="-1">Where can I get help? <a class="header-anchor" href="#where-can-i-get-help" aria-label="Permalink to &quot;Where can I get help?&quot;">​</a></h3><ul><li><strong>Community:</strong> <a href="https://github.com/imagodata/gispulse/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a> for questions and ideas</li><li><strong>Issues:</strong> <a href="https://github.com/imagodata/gispulse/issues" target="_blank" rel="noreferrer">GitHub Issues</a> for bug reports</li><li><strong>Pro support:</strong> email support included with Pro tier</li><li><strong>Enterprise support:</strong> dedicated support with 4h SLA</li><li><strong>Contact:</strong> <a href="mailto:contact@gispulse.dev" target="_blank" rel="noreferrer">contact@gispulse.dev</a></li></ul>`,58)])])}const g=t(r,[["render",o]]);export{c as __pageData,g as default};
